  ('T.D.7.24', (SELECT id FROM branslar WHERE slug = 'turkce'), 7, 1, '', 'Medya içeriğini farklı açılardan (amaç, hedef kitleye uygunluk, tutarlılık, olay/olaylar, karakterler, karakterlerin davranışları ile fiziksel ve psikolojik özellikleri, ileri sürülen görüşler, ana düşünce ve yardımcı düşünceler, hak ve özgürlükler, etik, değerler, dil-anlatım, ikna teknikleri, kaynak/konuşan/yazar vb.) değerlendirir.', 'Türkçe', 'ortaokul'),
  ('T.D.8.24', (SELECT id FROM branslar WHERE slug = 'turkce'), 8, 1, '', 'Medya içeriğini farklı açılardan (amaç, hedef kitleye uygunluk, tutarlılık, olay/olaylar, karakterler, karakterlerin davranışları ile fiziksel ve psikolojik özellikleri, ileri sürülen görüşler, ana düşünce ve yardımcı düşünceler, hak ve özgürlükler, etik, değerler, dil-anlatım, ikna teknikleri, kaynak/konuşan/yazar vb.) değerlendirir.', 'Türkçe', 'ortaokul'),
  ('T.D.5.23', (SELECT id FROM branslar WHERE slug = 'turkce'), 5, 1, '', 'Dinlediğinin/izlediğinin başlığını, içeriğini (olaylar, kahramanlar, kahramanların davranışları ve karakter özellikleri, ileri sürülen görüşler, ana düşünce ve yardımcı düşünceler, seçilen örnekler vb.) ön bilgilerini de kullanarak eleştirel açıdan ele alır ve eleştirinin odağındaki noktaya gerektiğinde alternatif önerir.', 'Türkçe', 'ortaokul'),
