  ('SB.6.3.4', (SELECT id FROM branslar WHERE slug = 'sosyal_bilgiler'), 6, 1, '', 'XI-XIII. yüzyıllar arasında meydana gelen siyasi faaliyetler ve askerî mücadelelerin Anadolu’nun Türkleşmesi ve İslamlaşmasına etkisini özetleyebilme', 'Sosyal Bilgiler', 'ortaokul'),
