  ('SB.7.3.1', (SELECT id FROM branslar WHERE slug = 'sosyal_bilgiler'), 7, 1, '', 'Osmanlı Devleti’nin cihan devleti hâline gelmesini sağlayan politikaları sorgulayabilme', 'Sosyal Bilgiler', 'ortaokul'),
