  ('SB.7.3.3', (SELECT id FROM branslar WHERE slug = 'sosyal_bilgiler'), 7, 1, '', 'Osmanlı kültür ve medeniyet unsurlarına ilişkin oluşturduğu ürünü paylaşabilme', 'Sosyal Bilgiler', 'ortaokul'),
