  ('TT.7.4.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Yapılan tasarımı paylaşmak için çoklu ortam sunusu hazırlayabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.5.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'İşlevsel özelliklerin mimari tasarımda yapısal farklılıklara yol açtığını algılayabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.5.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Farklı iklim ve coğrafi koşullardaki ihtiyaçlar için oluşturulmuş sinema salonu, konferans salonu, müze, tiyatro, spor salonu, cami vb. mekânları gözlemlemeleri istenir. Bu kapsamda Anadolu mimari tasarım örneklerinden biri olan geleneksel bir Türk evi ile dünyadan farklı mimari tasarım örneklerinden iglo, pagoda vb. tasarımlarını konu edinen bir film, video, animasyon öğrencilere izlettirilebilir ya da öğretmen tarafından hazırlanan sunu paylaşılabilir (OB4, OB5). Öğrencilerden izledikleri sunuda daha önce görmedikleri veya mimari tasarım açısından yeni fark ettik', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.5.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Kişisel ihtiyaçlarına ve farklı coğrafi şartlar ile iklim şartlarına uygun olarak tasarlayacakları konutu belirleyip çöl, kutup, kıyı şeridi, ormanlık, dağlık bölge gibi farklı iklim ve coğrafi şartlara uygun tasarıma yönelik inceleme ve araştırma yapmaları istenir. Tasarlayacakları konut ya da mekân tasarımına yönelik sürdürülebilir çözüm önerileri ve fikirler geliştirmeleri ve bunları defterlerine yazarak eskizler hazırlamaları sağlanır (SDB3.3). Tasarım oluşturulurken tüketim tercihlerini sürdürülebilirliğe katkıda bulunacak şekilde yapmaları ve tasarımlarında çevre', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.5.4', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Tasarımını sunmak için hangi tanıtım materyallerini kullanacağını planlayarak (tanıtım kartı, afiş, el broşürü, video, kısa film, bilgisayar destekli sunum vb.) tasarımlarını oluşturmaları', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.6.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Canlılar ve doğal yapıların yapısal, biçimsel ve görsel özelliklerini sanatsal gözlemleyebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.6.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Gündelik hayatında var olan bir problemi çözebilmek için doğa ve canlıları tasarımla ilişkilendirebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.6.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Gündelik hayatında var olan bir problemin çözümünde biyotaklit yaklaşımını kullanarak ürün oluşturabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.7.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Enerji kavramı, enerji kaynakları, türleri ve dönüşümleri hakkında bilgi toplayabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.7.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Enerjinin dönüşümünün ve korunumunun doğa ve insan hayatına etkisi üzerine tümevarımsal akıl yürütebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.7.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Yenilenebilir ve yenilenemez enerji kaynaklarını sınıflandırabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.7.4', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Yenilenemez enerji kaynakları kullanımının dünyaya etkisini gözleme dayalı tahmin edebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.7.5', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Yenilenebilir enerji kaynakları kullanılarak enerji elde edilebilen bir ürün taslağı oluşturabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.8.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'STEAM’i oluşturan disiplinler ile alt bileşenlerinin ne olduğunu sorgulayabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.8.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'STEAM disiplinlerinin arasındaki ilişkiyi gözlemleyebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.8.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'Proje türlerini karşılaştırabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.7.8.4', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 7, 1, '', 'STEAM yaklaşımına göre problem çözebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.1.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'İnovasyon ve AR-GE kavramlarını sorgulayabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.1.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'İnovatif bir ürünün taslağını oluşturabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.1.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Öğretmen öğrencilerden inovasyon içeren bir ürünün veya tasarımın kime ait olduğunu, korunmasının gerekliliğini, bu korumanın nasıl gerçekleştirileceğini, hangi yollarla ve nereden yapılarak fikrî ve sınai mülkiyet haklarını elde edilebileceğini sorgulamalarını ister. Her öğrenci, bir ürünü fikrî ve sınai mülkiyet hakları çerçevesinde nasıl koruyabileceğini araştırır (OB2). Öğrenciler inovatif ürünün taklit edilmemesi, izinsiz kullanılmaması ve yasal haklarının korunması için kullanacağı bilgi toplama araçlarını belirler. Bu aşamada emek ve fikirlerin korunmasının hak ve sorumlulukla', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.2.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Kurumlar veya şirketlere ait kurumsal kimlik çalışmalarını ve pazarlama tekniklerini genelleyebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.2.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'İnovatif ürünün tanıtım ve pazarlaması için çoklu ortam sunumu yapabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.3.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Görsel iletişim tasarımı kavramı, içeriği, türleri ve önemini sorgulayabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.3.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Öğretmen öğrencilere kitap, dergi, gazete, broşür gibi farklı yayın grafiği tasarım ürünlerinden örnekler sunar. Öğrencilerden bu yayın grafiği tasarımlarını inceleyerek içerdiği bileşenleri belirlemeleri istenir (OB4). Bu süreçte öğrenciler tipografi, başlık ve alt başlık düzenleri, sütun sistemleri, renk kullanımı, görsel konumlandırma, negatif alan kullanımı gibi yayın grafiği tasarım ürünlerine ilişkin parçaları belirler. Öğrenciler belirlenen tasarım bileşenlerinin yayın grafiği içindeki işlevini sorgular ve anlamaya çalışır. Örneğin bir gazete sayfasındaki görsellerin metin akı', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.3.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Öğrenciler ilk olarak günlük yaşamda karşılaştıkları bir problemi belirler (SDB3.3). Belirlenen problem, bir dergi kapağının hedef kitleye hitap etmemesi, bir gazete sayfasındaki okunabilirliğin düşük olması, bir dergi sayfası tasarımındaki renk kullanımı veya bir broşürün daha bilgilendirici hâle getirilmesi gibi konular olabilir. Öğrencilerden seçtikleri tasarım problemini daha iyi anlamak için konu veya tema hakkında araştırma ve inceleme yapmaları istenir (OB1). Bu süreçte öğrenciler seçtikleri yayın 67 TEKNOLOJİ VE TASARIM DERSI ÖĞRETIM PROGRAMI türüyle ilgili örnekleri inceley', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.4.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Ergonomi ve tasarım ilişkisini sorgulayabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.4.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Ürünleri ergonomik açıdan gözlemleyebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.4.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Ergonomik bir ürün oluşturabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.5.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Mühendislik ve tasarım arasındaki ilişkiyi sorgulayabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.5.2', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Çevresindeki ürünleri mühendislik açısından inceleyerek tasarım süreçlerini gözlemleyebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.5.3', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Mühendislik tasarım sürecindeki sınırlılıkları değerlendirebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.5.4', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Tasarım ürünü oluşturabilme', 'Teknoloji ve Tasarım', 'ortaokul'),
  ('TT.8.6.1', (SELECT id FROM branslar WHERE slug = 'teknoloji_tasarim'), 8, 1, '', 'Ulaşım araçlarının tasarımında dikkate alınan temel prensipleri genelleyebilme', 'Teknoloji ve Tasarım', 'ortaokul'),
