-- Migration 030: Kazanımları yeniden seed et — MEB Türkiye Yüzyılı Maarif Modeli 2025
-- 24 JSON dosyasından üretildi, toplam 3518 kazanım.
-- İlkokul + ortaokul + iho (eski veri) temizlendi, yeni müfredatla değiştirildi.

-- 1. Eski ilkokul/ortaokul/iho kazanımlarını temizle
DELETE FROM kazanimlar WHERE okul_tipi IN ('ilkokul', 'ortaokul', 'iho');

-- 2. Yeni kazanımları ekle
ON CONFLICT (kod) DO UPDATE SET
  brans_id  = EXCLUDED.brans_id,
  sinif     = EXCLUDED.sinif,
  unite_no  = EXCLUDED.unite_no,
  unite_ad  = EXCLUDED.unite_ad,
  ad        = EXCLUDED.ad,
  ders      = EXCLUDED.ders,
  okul_tipi = EXCLUDED.okul_tipi;